('Deportes', 'WWE 2K25 ofrece la experiencia más realista de la lucha libre profesional, con modos de carrera, torneos y un extenso roster de superestrellas WWE.', '2025-03-14', 'https://i.pinimg.com/1200x/c7/ac/6d/c7ac6d5ef0a6ec03e70bdcf4de6e66be.jpg', 'PS5', 'https://assets.nintendo.com/image/upload/f_auto/q_auto/dpr_1.5/c_scale,w_400/store/software/switch2/70010000097826/2fef9ae0ce3c03fc5066e028fb9d0ca997b502a2a7cb6853911a623b18cf96c2', 199.00, NULL, NULL, 'WWE 2K25'),
('Deportes', 'EA Sports PGA Tour trae el golf de élite con campos reales, torneos oficiales del PGA Tour y gráficos impresionantes con la tecnología Frostbite.', '2023-03-24', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSM4MP84W3a98UPMNdzUHcURKoeWP9alW3Scw&s', 'PS5', 'https://shared.fastly.steamstatic.com/store_item_assets/steam/apps/1677350/capsule_616x353.jpg?t=1777395708', 149.00, NULL, NULL, 'EA Sports PGA Tour'),
('Deportes', 'Tony Hawk''s Pro Skater 1+2 es un remake de los dos juegos clásicos de skateboarding con gráficos modernos, todos los trucos originales y una banda sonora legendaria.', '2020-09-04', 'https://i.pinimg.com/736x/7d/43/1d/7d431db6f76e6b73506f9dd134e230c3.jpg', 'PS5', 'https://i.pinimg.com/1200x/1e/9a/eb/1e9aebe2ef16bdd53f2e091b8ae81344.jpg', 99.00, NULL, NULL, 'Tony Hawk''s Pro Skater 1+2'),
('Deportes', 'Riders Republic es un juego de deportes extremos en mundo abierto donde los jugadores compiten en carreras de bicicletas, esquí, snowboard y wingsuit en parques nacionales de EE.UU.', '2021-10-28', 'https://i.pinimg.com/1200x/d3/c0/a9/d3c0a9cf2c618a06038439ae2fe72db0.jpg', 'PS5', 'https://i.pinimg.com/1200x/b0/d9/8a/b0d98a9b858531665f5a99cd96cb5e8f.jpg', 79.00, NULL, NULL, 'Riders Republic'),
('Deportes', 'Need for Speed Heat es un juego de carreras callejeras de mundo abierto ambientado en Palm City, donde los jugadores compiten en eventos legales durante el día y carreras clandestinas por la noche mientras evaden a la policía.', '2019-11-08', 'https://i.pinimg.com/1200x/35/a4/e7/35a4e7a2ea56e19add8525b5e665fc0d.jpg', 'PS5', 'https://i.pinimg.com/1200x/24/79/4c/24794c644ba273f23870d9e296ff3bc5.jpg', 149.00, NULL, NULL, 'Need for Speed Heat'),
('Deportes', 'Need for Speed Unbound ofrece carreras urbanas de alta velocidad con un estilo visual único inspirado en el arte callejero, personalización avanzada de vehículos y emocionantes persecuciones policiales.', '2022-12-02', 'https://upload.wikimedia.org/wikipedia/en/thumb/d/db/Need_for_Speed_Unbound.png/250px-Need_for_Speed_Unbound.png', 'PS5', 'https://shared.fastly.steamstatic.com/store_item_assets/steam/apps/1846380/7db34cfa0adc634dfcb732563450dc4b1da9d1f2/capsule_616x353.jpg?t=1777394467', 79.00, NULL, NULL, 'Need for Speed Unbound'),
('Deportes', 'Skate 3 es el clásico juego de skateboarding en mundo abierto donde los jugadores recorren las calles de Port Carverton realizando trucos, desafíos y compitiendo en equipo.', '2010-05-11', 'https://upload.wikimedia.org/wikipedia/en/8/84/Skate-3-Boxart.jpg', 'PS5', 'https://media.contentapi.ea.com/content/dam/gin/images/2017/01/skate-3-key-art.jpg.adapt.crop191x100.628p.jpg', 149.00, NULL, NULL, 'Skate 3'),
('Deportes', 'Steep es un juego de deportes de invierno en mundo abierto donde los jugadores exploran los Alpes practicando esquí, snowboard, wingsuit y parapente en un vasto terreno montañoso.', '2016-12-02', 'https://i.pinimg.com/736x/7c/24/8e/7c248e59bd8736f919cfbb51848e2989.jpg', 'PS5', 'https://i.pinimg.com/1200x/b2/30/9c/b2309c53a6060e4110883a4236357842.jpg', 49.00, NULL, NULL, 'Steep'),
('Deportes', 'WRC 24 es el simulador oficial del Campeonato Mundial de Rally, con todos los pilotos, equipos y recorridos de la temporada 2024, además de modos carrera y multijugador.', '2024-10-01', 'https://i.pinimg.com/736x/0a/79/0a/0a790ac29bfe687f259568c5cf7dc66c.jpg', 'PS5', 'https://image.api.playstation.com/vulcan/ap/rnd/202409/2522/691eab9e41e3822072608b1b1cc1710ee95af7ae6cc77a8b.jpg', 149.00, NULL, NULL, 'WRC 24');

